import time
import boto3
from botocore.config import Config
from botocore.exceptions import ClientError
import json


sqs = boto3.client('sqs',config=Config(region_name='us-west-1'))



queueUrl = 'YourSQSQueueURL'
# Create the queue. This returns an empty response body

# Send a message to SQS
def send(message):
    try:
        sqs.send_message(
            QueueUrl=queueUrl,
            DelaySeconds=10,
            MessageBody=(message)
        )
    except ClientError as e:
        print(e.response['Error']['Message'])
        return False
    else:
        return True

def send_messages():

    try:

        with open('input-data/user_data.json', 'r') as f:
            data = json.load(f)

        for user in data["users"]:
            message_data = user

            # Sending the Message
            print(send(message=str(message_data)))
    except ClientError as e:
        print(e.response['Error']['Message'])

if __name__ == '__main__':

    print("Starting Program...")

    while True:
        # Send Messages
        send_messages()

        time.sleep(30) # Sleep for 3 minutes